import numpy as np
golden = np.zeros((32,32), dtype=complex)
for idx in range(32):
    if idx < 16:
        golden[idx, idx] = 1.0
    else:
        y = idx - 16
        ty = (2 * y) % 15 if y < 15 else 15
        golden[16 + ty, idx] = 1.0

